// Script Continued Below
// STRY0074135 - the parent task for the grafted in template did not update to set the child template run
updateChildTemplateRunOnTasks();

function updateChildTemplateRunOnTasks(){
	var grTempInst = new GlideRecord("x_153465_discovert_discover_routing_runtime");
	var grTask = new GlideRecord("x_153465_discovert_route_task_instance");

	grTempInst.addNotNullQuery('parent_task');
	grTempInst.query();
	while(grTempInst.next()){
		if(grTask.get(grTempInst.parent_task)){
			grTask.child_route_template = grTempInst.parent_task;
			grTask.update();
		}
	}
}
